const buildBackgroundIconKey = ({
  form,
  reverse,
  color,
  gradientDirection,
}: DrugsCardBackgroundImage): string =>
  `form=${form}, reverse=${reverse}, color=${color}, gradientDirection=${gradientDirection}`;

export const getDrugsCardBackgroundIcon = (
  backgroundImage: DrugsCardBackgroundImage,
): BackgroundIconComponent => {
  const fallbackKeys = [
    buildBackgroundIconKey(backgroundImage),
    buildBackgroundIconKey({...backgroundImage, reverse: 0}),
    buildBackgroundIconKey(DEFAULT_BACKGROUND_IMAGE),
  ];

  for (const iconKey of fallbackKeys) {
    const icon = iconByBackgroundParams[iconKey];
    if (icon) {
      return icon;
    }
  }

  return iconByBackgroundParams[buildBackgroundIconKey(DEFAULT_BACKGROUND_IMAGE)]!;
};

export {DEFAULT_BACKGROUND_IMAGE};
